// Normalize booking data from different platforms (Calendly, Cal.com, etc.)
const raw = $input.first().json;
const body = raw.body || raw.payload || raw;

// Support Calendly format
const calendlyPayload = body.payload;
const isCalendly = !!calendlyPayload;

let booking = {};

if (isCalendly) {
  // Calendly v2 webhook format
  const invitee = calendlyPayload.invitee || {};
  const event = calendlyPayload.event || {};
  booking = {
    platform: 'Calendly',
    guestName: invitee.name || '',
    guestEmail: invitee.email || '',
    meetingTitle: event.name || 'Meeting',
    startTime: event.start_time || '',
    endTime: event.end_time || '',
    meetingUrl: event.location?.join_url || event.location?.location || '',
    cancelUrl: invitee.cancel_url || '',
    rescheduleUrl: invitee.reschedule_url || '',
    timezone: invitee.timezone || 'UTC',
    questions: invitee.questions_and_answers || []
  };
} else {
  // Generic format - normalize common field names
  booking = {
    platform: body.platform || 'Unknown',
    guestName: body.name || body.guest_name || body.attendee_name || '',
    guestEmail: body.email || body.guest_email || body.attendee_email || '',
    meetingTitle: body.event_type || body.meeting_type || body.title || 'Meeting',
    startTime: body.start_time || body.scheduled_at || body.start || '',
    endTime: body.end_time || body.end || '',
    meetingUrl: body.meeting_url || body.join_url || body.location || '',
    cancelUrl: body.cancel_url || '',
    rescheduleUrl: body.reschedule_url || '',
    timezone: body.timezone || 'UTC',
    questions: []
  };
}

// Format the date nicely
let formattedDate = 'TBD';
let formattedTime = 'TBD';
if (booking.startTime) {
  const dt = new Date(booking.startTime);
  formattedDate = dt.toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
  formattedTime = dt.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });
}

const bookingId = 'BK-' + Date.now();

return [{
  json: {
    ...booking,
    bookingId,
    formattedDate,
    formattedTime,
    receivedAt: new Date().toISOString()
  }
}];

// Filter for bookings tomorrow and send reminders
const items = $input.all();
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);
tomorrow.setHours(0, 0, 0, 0);

const dayAfter = new Date(tomorrow);
dayAfter.setDate(dayAfter.getDate() + 1);

const tomorrowBookings = items.filter(item => {
  const b = item.json;
  if (b.Status === 'Cancelled' || !b.Date || !b.Guest_Email) return false;

  // Try to parse the date from the sheet
  const bookingDate = new Date(b.Date);
  return bookingDate >= tomorrow && bookingDate < dayAfter;
});

if (tomorrowBookings.length === 0) {
  return [{ json: { noReminders: true } }];
}

return tomorrowBookings;
